I threw the reproduction case into pprof and it seems I was probably mistaken, about 3.5 of the 4 minutes are actually attributed to sha256sum. So its probably a case of excessive hashing and not compression occuring where it shouldnt.

Example patch for profiling

```diff
diff --git a/cmd/podman/images/build.go b/cmd/podman/images/build.go
index 04fdeab0a..d7cae004b 100644
--- a/cmd/podman/images/build.go
+++ b/cmd/podman/images/build.go
@@ -3,8 +3,10 @@ package images
 import (
 	"io"
 	"io/ioutil"
+	"log"
 	"os"
 	"path/filepath"
+	"runtime/pprof"
 	"strings"
 	"time"

@@ -25,6 +27,8 @@ import (
 	"github.com/spf13/cobra"
 )

+var cpuprofile string
+
 // buildFlagsWrapper are local to cmd/ as the build code is using Buildah-internal
 // types.  Hence, after parsing, we are converting buildFlagsWrapper to the entities'
 // options which essentially embed the Buildah types.
@@ -101,6 +105,7 @@ func buildFlags(cmd *cobra.Command) {

 	// Podman flags
 	flags.BoolVarP(&buildOpts.SquashAll, "squash-all", "", false, "Squash all layers into a single layer")
+	flags.StringVarP(&cpuprofile, "cpuprofile", "", "", "write cpu profile to file")

 	// Bud flags
 	budFlags := buildahCLI.GetBudFlags(&buildOpts.BudResults)
@@ -182,6 +187,15 @@ func build(cmd *cobra.Command, args []string) error {
 		return errors.New("cannot specify --squash, --squash-all and --layers options together")
 	}

+	if cpuprofile != "" {
+		f, err := os.Create(cpuprofile)
+		if err != nil {
+			log.Fatal(err)
+		}
+		pprof.StartCPUProfile(f)
+		defer pprof.StopCPUProfile()
+	}
+
 	// Extract container files from the CLI (i.e., --file/-f) first.
 	var containerFiles []string
 	for _, f := range buildOpts.File {
```

Run the same reproduction command but with `--cpuprofile=profile.pprof` and then view with `go tool pprof -web profile.pprof`
